#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b) {
    /* Acquire raw pointers for fast indexing */
    const double* __restrict b_ptr = b.data();
    double* __restrict x_ptr = x.data();
    std::vector<double*> L_ptrs(n);
    for (int i = 0; i < n; ++i)
        L_ptrs[i] = L[i].data();

    /* Each loop iteration is independent, so we can parallelise */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = b_ptr[i];
        double* __restrict Li = L_ptrs[i];
        double* __restrict x_prev = x_ptr;
        for (int j = 0; j < i; ++j) {
            sum -= Li[j] * x_prev[j];
        }
        /* L[i][i] is always guaranteed non‑zero for a triangular solve */
        x_ptr[i] = sum / Li[i];
    }
}
