/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_lu(int n, std::vector<std::vector<double>>& A) {
    /* Parallelise over the outermost loop (rows). */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        /* First stage: compute the i‑th column (j < i). */
        for (int j = 0; j < i; ++j) {
            double* Aik  = &A[i][0];
            double  sum  = 0.0;
            for (int k = 0; k < j; ++k) {
                sum += Aik[k] * A[k][j];
            }
            A[i][j] -= sum;
            A[i][j] /= A[j][j];
        }

        /* Second stage: update the rest of the row (j ≥ i). */
        for (int j = i; j < n; ++j) {
            double* Aik = &A[i][0];
            double  sum = 0.0;
            for (int k = 0; k < i; ++k) {
                sum += Aik[k] * A[k][j];
            }
            A[i][j] -= sum;
        }
    }
}
