/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    // => Form  B := alpha*A**T*B.
    // A is MxM
    // B is MxN

    // Fetch row pointers for faster indexing
    std::vector<double*> A_rows(m), B_rows(m);
    for (int i = 0; i < m; ++i) {
        A_rows[i] = A[i].data();
        B_rows[i] = B[i].data();
    }

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double* Ai = A_rows[i];
        double* Bi = B_rows[i];
        for (int j = 0; j < n; ++j) {
            double sum = 0.0;
            // k runs from i+1 to m-1
            for (int k = i + 1; k < m; ++k) {
                sum += A_rows[k][i] * B_rows[k][j];
            }
            Bi[j] = alpha * (sum + Bi[j]);
        }
    }
}
