#include <vector>
#include <omp.h>

void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    /* --------------------------------------------------------------------
       Compute column means (parallelised)
       -------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += data[i][j];
        mean[j] = sum / n;
    }

    /* --------------------------------------------------------------------
       Subtract means (parallelised)
       -------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] -= mean[j];
        }
    }

    /* --------------------------------------------------------------------
       Upper‑triangular covariance calculation, copy to lower‑triangular
       -------------------------------------------------------------------- */
    // The innermost loop is the most expensive, so we parallelise over rows
    #pragma omp parallel for schedule(dynamic, 1)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            double val = sum / (n - 1.0);
            cov[i][j] = val;
            cov[j][i] = val;           // symmetry
        }
    }
}
