#include <vector>
#include <numeric>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
		    double alpha,
		    double beta,
		    std::vector<std::vector<double>>& A,
		    std::vector<std::vector<double>>& B,
		    std::vector<double>& tmp,
		    std::vector<double>& x,
		    std::vector<double>& y) {

    /* Flatten the 2‑D input matrices into 1‑D strides for
       better cache locality and easier vectorisation.  */
    std::vector<double> a_flat(n * n);
    std::vector<double> b_flat(n * n);

    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j) {
            a_flat[i * n + j] = A[i][j];
            b_flat[i * n + j] = B[i][j];
        }

    /* Local copies for thread safety.  */
    std::vector<double> x_local = x;

    /* Parallelise the outer loop over rows.  */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double tmp_i = 0.0;
        double y_i   = 0.0;
        int base = i * n;
        for (int j = 0; j < n; ++j) {
            double xj = x_local[j];
            tmp_i += a_flat[base + j] * xj;
            y_i   += b_flat[base + j] * xj;
        }
        tmp[i] = tmp_i;
        y[i]   = alpha * tmp_i + beta * y_i;
    }
}
