#include <vector>
#include <omp.h>

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C) {
    // Parallel over the outer dimension (rows of C)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* const ci  = C[i].data();   // row i of C
        const double* const ai = A[i].data(); // row i of A

        // Apply the beta scaling to the entire row of C
        for (int j = 0; j < nj; ++j) {
            ci[j] *= beta;
        }

        // Inner product loops
        for (int k = 0; k < nk; ++k) {
            double aik = alpha * ai[k];      // pre-multiply A[i][k]
            const double* const bk = B[k].data(); // row k of B
            for (int j = 0; j < nj; ++j) {
                ci[j] += aik * bk[j];
            }
        }
    }
}
