#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    // Flatten the 2‑D vectors into 1‑D blocks for better cache usage.
    const int strideC = n;
    const int strideB = n;
    const int strideA = m;

    // Pre‑compute linear addresses for A and B row starts.
    std::vector<int> a_start(m), b_start(m);
    for (int i = 0; i < m; ++i) {
        a_start[i] = i * strideA;
        b_start[i] = i * strideB;
    }

    // Parallelise the outer two loops using collapse to get good load balance.
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            double temp2 = 0.0;

            // Compute the contribution of the lower triangular part.
            for (int k = 0; k < i; ++k) {
                double aik = A[a_start[i] + k];
                double bkj = B[b_start[k] + j];
                double bik = B[b_start[i] + j] * aik;

                C[k * strideC + j] += alpha * bik;
                temp2 += bkj * aik;
            }

            // Final update for C[i][j].
            double aii = A[a_start[i] + i];
            C[i * strideC + j] = beta * C[i * strideC + j]
                                 + alpha * B[b_start[i] + j] * aii
                                 + alpha * temp2;
        }
    }
}
