```cpp
#include <vector>
#include <cstring>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B)
{
    // Pointers to the underlying contiguous storage of each matrix
    double* Cp = &C[0][0];
    double* Ap = &A[0][0];
    double* Bp = &B[0][0];
    const double aalpha = alpha;

#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // row pointer for C[i]
        double* Ci = Cp + i * n;
        // column pointer for B[i]
        double* Bi = Bp + i * m;

        // lower triangular part of C[i] multiplied by beta
        for (int j = 0; j <= i; ++j)
            Ci[j] *= beta;

        // Main syr2k update
        for (int k = 0; k < m; ++k) {
            double aik = Ap + k * n;   // column k of A
            double bik = Bi[k];        // B[i][k]
            for (int j = 0; j <= i; ++j) {
                double ajk = aik[j];   // A[j][k]
                double bjk = Bp + j * m; // row j of B
                Ci[j] += ajk * aalpha * bik + bjk[k] * aalpha * Ai[k];
            }
        }
    }
}
