```cpp
#include <cmath>
#include <vector>
#include <omp.h>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev)
{
    const double eps   = 0.1;
    const double sqrtn = std::sqrt(static_cast<double>(n));

    /* ---------- 1. compute column means (parallel across columns) ---------- */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += data[i][j];
        mean[j] = sum / double(n);
    }

    /* ---------- 2. compute column stddevs (parallel across columns) --------- */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sumsq = 0.0;
        const double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            double diff = data[i][j] - mu;
            sumsq += diff * diff;
        }
        double sdev = std::sqrt(sumsq / double(n));
        stddev[j] = (sdev <= eps) ? 1.0 : sdev;
    }

    /* ---------- 3. normalise data (parallel across rows) ------------------- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] = (data[i][j] - mean[j]) / (sqrtn * stddev[j]);
        }
    }

    /* ---------- 4. compute correlation matrix (upper‑triangular only) -------- */
    /* The lower‑triangular part is set after the upper one to avoid race.    */
#pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k)
                sum += data[k][i] * data[k][j];
            corr[i][j] = sum;
            corr[j][i] = sum;          // symmetry
        }
    }
}
