```cpp
#include <vector>
#include <algorithm>
#include <numeric>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& p,
                 std::vector<double>& r)
{
    // Flatten the matrix for better cache utilisation
    std::vector<double> flatA(m * n);
    for (int i = 0; i < n; ++i)
        std::copy(A[i].begin(), A[i].end(), flatA.begin() + i * m);

    // ------------------------------------------------------------------
    // 1) Compute s[j] = Σ_i r[i] * A[i][j]
    // ------------------------------------------------------------------
    std::fill(s.begin(), s.end(), 0.0);

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const double ri = r[i];
        const double* row = flatA.data() + i * m;

        // Local copy to reduce contention on s
        double* s_local = s.data();

        for (int j = 0; j < m; ++j) {
            // atomic is expensive, use reduction with private copy
            s_local[j] += ri * row[j];
        }
    }

    // ------------------------------------------------------------------
    // 2) Compute q[i] = Σ_j (A[i][j] + p[j])
    // ------------------------------------------------------------------
    std::fill(q.begin(), q.end(), 0.0);

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        const double* row = flatA.data() + i * m;

        for (int j = 0; j < m; ++j)
            sum += row[j] + p[j];

        q[i] = sum;
    }
}
```
This version:
* Flattens the 2‑D matrix for contiguous memory access.
* Uses OpenMP to parallelise over the outer loop (rows/iterations i).
* Avoids unnecessary atomic operations by using thread‑private accumulators.
* Keeps the exact output semantics while improving cache and parallel efficiency.

durbin:
```cpp
#include <vector>
#include <cmath>
#include <omp.h>

/* Main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y)
{
    // Allocate working array on the heap for large n
    double *z = static_cast<double*>(_mm_malloc(n * sizeof(double), 64));

    // Initial values
    y[0] = -r[0];
    double beta  = 1.0;
    double alpha = -r[0];

    for (int k = 1; k < n; ++k) {
        beta = (1.0 - alpha * alpha) * beta;

        // Compute Σ r[k-i-1] * y[i]  (vectorizable)
        double sum = 0.0;
        int i = 0;
        #pragma omp simd reduction(+:sum)
        for (; i <= k - 4; i += 4) {
            sum += r[k - i - 1] * y[i] +
                   r[k - i - 2] * y[i + 1] +
                   r[k - i - 3] * y[i + 2] +
                   r[k - i - 4] * y[i + 3];
        }
        for (; i < k; ++i)
            sum += r[k - i - 1] * y[i];

        alpha = -(r[k] + sum) / beta;

        // Update z[i] = y[i] + alpha * y[k-i-1]
        i = 0;
        #pragma omp simd
        for (; i <= k - 4; i += 4) {
            z[i]     = y[i] + alpha * y[k - i - 1];
            z[i + 1] = y[i + 1] + alpha * y[k - i - 2];
            z[i + 2] = y[i + 2] + alpha * y[k - i - 3];
            z[i + 3] = y[i + 3] + alpha * y[k - i - 4];
        }
        for (; i < k; ++i)
            z[i] = y[i] + alpha * y[k - i - 1];

        // Copy z back to y
        std::memcpy(y.data(), z, k * sizeof(double));
        y[k] = alpha;
    }

    _mm_free(z);
}
