#include <cmath>
#include <vector>
#include <omp.h>

/* Main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n,
		     std::vector<std::vector<double>>& A) {
    /* Parallelise the outermost loop; each iteration writes only
       to row `i` of `A`, so there are no write‑write conflicts. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        /* Working with raw pointers is a bit faster than
           `operator[]` on std::vector in the inner loops. */
        double* Ai = A[i].data();
        double* Aii = &Ai[i];                 // pointer to A[i][i]
        double diag = *Aii;

        /* --- off‑diagonal elements (j < i) --- */
        for (int j = 0; j < i; ++j) {
            double* Aj = A[j].data();
            double sum = 0.0;

            for (int k = 0; k < j; ++k) {
                sum += Ai[k] * Aj[k];
            }

            Ai[j] = (Ai[j] - sum) / Aj[j];
        }

        /* --- diagonal element --- */
        double sum = 0.0;
        for (int k = 0; k < i; ++k) {
            sum += Ai[k] * Ai[k];
        }
        *Aii = std::sqrt(diag - sum);
    }
}
