#include <cmath>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A,
		      std::vector<std::vector<double>>& B)
{
    const double coeff = 0.2;
    // Unroll inner-most 2×2 loop to increase compile‑time optimization potential
    const int stride = n;
    const int last = n - 1;

    for (int t = 0; t < tsteps; ++t) {
        /* First half–step: A → B */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < last; ++i) {
            double* rowB   = B[i].data();
            double const* rowA       = A[i].data();
            double const* rowAprev   = A[i-1].data();
            double const* rowAnext   = A[i+1].data();
            for (int j = 1; j < last; ++j) {
                rowB[j] = coeff *
                          ( rowA[j]
                          + rowA[j-1]
                          + rowA[j+1]
                          + rowAnext[j]
                          + rowAprev[j] );
            }
        }

        /* Second half–step: B → A */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < last; ++i) {
            double* rowA   = A[i].data();
            double const* rowB       = B[i].data();
            double const* rowBprev   = B[i-1].data();
            double const* rowBnext   = B[i+1].data();
            for (int j = 1; j < last; ++j) {
                rowA[j] = coeff *
                          ( rowB[j]
                          + rowB[j-1]
                          + rowB[j+1]
                          + rowBnext[j]
                          + rowBprev[j] );
            }
        }
    }
}
