void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A)
{
    // Quick exit for degenerate cases – identical to the original semantics.
    if (tsteps <= 0 || n <= 2) return;

    const double inv9 = 1.0 / 9.0;

    // Iterate over time steps sequentially; parallelise spatial loops.
    for (int t = 0; t < tsteps; ++t) {
        // Parallelise across the two spatial dimensions with a at most
        // two‑level collapse.  The limit is 8 threads so we run 2‑D loop
        // parallelism – this is the usual choice for stencil codes.
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i <= n - 2; ++i) {
            // Cache pointers to the three relevant rows; reduces repeated
            // vector indexing (A[i-1], A[i], A[i+1]) inside the j‑loop.
            double* const prevRow = A[i-1].data();
            double* const currRow = A[i].data();
            double* const nextRow = A[i+1].data();

            for (int j = 1; j <= n - 2; ++j) {
                currRow[j] = ( prevRow[j-1] + prevRow[j] + prevRow[j+1]
                              + currRow[j-1] + currRow[j] + currRow[j+1]
                              + nextRow[j-1] + nextRow[j] + nextRow[j+1]
                            ) * inv9;
            }
        }
    }
}
