    // 1st phase: I×J = I×K * K×J   (alpha * A * B)
    // -------------------------------------------------
#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double *a_row = A[i].data();
        double *tmp_row = &tmp_flat[i * nj];
        // For each column of B, we will accumulate over k
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            double const *b_col_ptr = nullptr; // placeholder
            for (int k = 0; k < nk; ++k) {
