   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {
    // Initialise y to zero once outside the parallel region
    #pragma omp parallel for
    for (int i = 0; i < n; ++i) y[i] = 0.0;

    // Parallel block: each iteration over i is independent, so we can
    // compute tmp[i] and update y in one go.
    // Use array reduction on y to avoid explicit synchronisation.
    #pragma omp parallel for schedule(static) reduction(+: y)
    for (int i = 0; i < m; ++i) {
        const double* rowA = A[i].data();
        double t = 0.0;
        // compute tmp[i]
        for (int j = 0; j < n; ++j) {
            t += rowA[j] * x[j];
        }
        tmp[i] = t;  // store tmp for potential future use

        // update y
        for (int j = 0; j < n; ++j) {
            y[j] += rowA[j] * t;
        }
    }
}
