/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z)
{
    /* Flattened access to the 2‑D matrix for better cache behaviour. */
    const std::size_t stride = A[0].size();              // stride == n
    double* A_flat = static_cast<double*>(const_cast<double*>(A[0].data()));
    double* u1_ptr = u1.data();
    double* v1_ptr = v1.data();
    double* u2_ptr = u2.data();
    double* v2_ptr = v2.data();
    double* w_ptr  = w.data();
    double* x_ptr  = x.data();
    double* y_ptr  = y.data();
    double* z_ptr  = z.data();

    /* 1. Rank‑1 updates to A: A = A + u1*v1ᵀ + u2*v2ᵀ */
    #pragma omp parallel for
    for (std::size_t i = 0; i < n; ++i)
    {
        double ui1 = u1_ptr[i];
        double ui2 = u2_ptr[i];
        double* Ai = A_flat + i * stride;
        for (std::size_t j = 0; j < n; ++j)
        {
            Ai[j] += ui1 * v1_ptr[j] + ui2 * v2_ptr[j];
        }
    }

    /* 2. x = x + beta * Aᵀ * y  (Aᵀ  is accessed by swapping indices) */
    #pragma omp parallel for
    for (std::size_t i = 0; i < n; ++i)
    {
        double xi = x_ptr[i];
        for (std::size_t j = 0; j < n; ++j)
        {
            xi += beta * (A_flat + j * stride)[i] * y_ptr[j];
        }
        x_ptr[i] = xi;
    }

    /* 3. x = x + z   (trivial, but keep parallel for consistency) */
    #pragma omp parallel for
    for (std::size_t i = 0; i < n; ++i)
        x_ptr[i] += z_ptr[i];

    /* 4. w = w + alpha * A * x */
    #pragma omp parallel for
    for (std::size_t i = 0; i < n; ++i)
    {
        double wi = w_ptr[i];
        double* Ai = A_flat + i * stride;
        for (std::size_t j = 0; j < n; ++j)
        {
            wi += alpha * Ai[j] * x_ptr[j];
        }
        w_ptr[i] = wi;
    }
}
