void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {

    const double A_val  = alpha;
    const double B_val  = beta;

    /* Parallelise over the rows of C.  Each thread works on a
       disjoint set of rows, so no lock is necessary. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        std::vector<double>& Ci = C[i];

        /* Scale the lower‑triangular part of the row. */
        for (int j = 0; j <= i; ++j)
            Ci[j] *= B_val;

        /* Update the lower‑triangular part using the k‑loop. */
        for (int k = 0; k < m; ++k) {
            const double aik = A[i][k];          /* A[i][k] once per k */
            for (int j = 0; j <= i; ++j)
                Ci[j] += A_val * aik * A[j][k];
        }
    }
}
