/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    // Alias for faster indexing
    auto Aptr = reinterpret_cast<const double**>(nullptr);
    auto Rptr = reinterpret_cast<double **>(nullptr);
    auto Qptr = reinterpret_cast<double **>(nullptr);
    for (int i = 0; i < m; ++i) {
        Rptr[i] = R[i].data();
        Qptr[i] = Q[i].data();
    }
    for (int k = 0; k < n; ++k) {
        // Step 1: compute norm of column k of A
        double nrm = 0.0;
        #pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i) {
            double v = A[i][k];
            nrm += v * v;
        }
        Rptr[k][k] = std::sqrt(nrm);

        // Step 2: compute k-th column of Q
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Qptr[i][k] = A[i][k] / Rptr[k][k];
        }

        // Step 3: orthogonalize remaining columns
        for (int j = k + 1; j < n; ++j) {
            double dot = 0.0;
            #pragma omp parallel for reduction(+:dot) schedule(static)
            for (int i = 0; i < m; ++i) {
                dot += Qptr[i][k] * A[i][j];
            }
            Rptr[k][j] = dot;
            #pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                A[i][j] -= Qptr[i][k] * dot;
            }
        }
    }
}
