/* Optimised computational kernel.
 * The function interface is unchanged, but the implementation
 * has been rewritten to minimise memory traffic, use pointer
 * arithmetic and parallelise the outer loops.
 */
void kernel_mvt(int n,
                std::vector<double>& x1,
                std::vector<double>& x2,
                std::vector<double>& y_1,
                std::vector<double>& y_2,
                std::vector<std::vector<double>>& A) {

    // ------------------------------------------------------------------
    // First phase:  x1[i] += ∑_j A[i][j] * y_1[j]
    // ------------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double *Ai   = A[i].data();           // row i
        double &xi1  = x1[i];                 // reference to reduce indexing
        const double *y1 = y_1.data();

        // Unroll the inner loop to reduce branch overhead
        int j = 0;
        for (; j <= n - 8; j += 8) {
            xi1 += Ai[j]     * y1[j];
            xi1 += Ai[j + 1] * y1[j + 1];
            xi1 += Ai[j + 2] * y1[j + 2];
            xi1 += Ai[j + 3] * y1[j + 3];
            xi1 += Ai[j + 4] * y1[j + 4];
            xi1 += Ai[j + 5] * y1[j + 5];
            xi1 += Ai[j + 6] * y1[j + 6];
            xi1 += Ai[j + 7] * y1[j + 7];
        }
        for (; j < n; ++j) {
            xi1 += Ai[j] * y1[j];
        }
    }

    // ------------------------------------------------------------------
    // Second phase:  x2[i] += ∑_j A[j][i] * y_2[j]
    // ------------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double &xi2    = x2[i];
        const double *y2 = y_2.data();

        // Because A is stored row‑major, accessing A[j][i]
        // causes a stride.  We loop over j, fetching the
        // required column element by pointer arithmetic.
        int j = 0;
        for (; j <= n - 8; j += 8) {
            xi2 += A[j][i]     * y2[j];
            xi2 += A[j + 1][i] * y2[j + 1];
            xi2 += A[j + 2][i] * y2[j + 2];
            xi2 += A[j + 3][i] * y2[j + 3];
            xi2 += A[j + 4][i] * y2[j + 4];
            xi2 += A[j + 5][i] * y2[j + 5];
            xi2 += A[j + 6][i] * y2[j + 6];
            xi2 += A[j + 7][i] * y2[j + 7];
        }
        for (; j < n; ++j) {
            xi2 += A[j][i] * y2[j];
        }
    }
}
