/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_fdtd_2d(int tmax,
                    int nx,
                    int ny,
                    std::vector<std::vector<double>>& ex,
                    std::vector<std::vector<double>>& ey,
                    std::vector<std::vector<double>>& hz,
                    std::vector<double>& _fict_) {

    const double c1 = 0.5;
    const double c2 = 0.7;

    for (int t = 0; t < tmax; ++t) {

        /* 1. Update ey at i = 0 (boundary) – no parallelisation needed */
        double val = _fict_[t];
        for (int j = 0; j < ny; ++j)
            ey[0][j] = val;

        /* 2. Update ey for i = 1..nx-1 */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < nx; ++i) {
            double *ey_ptr   = ey[i].data();
            const double *hz_ptr   = hz[i].data();
            const double *hz_prev_ptr = hz[i-1].data();
            for (int j = 0; j < ny; ++j)
                ey_ptr[j] -= c1 * (hz_ptr[j] - hz_prev_ptr[j]);
        }

        /* 3. Update ex for j = 1..ny-1 */
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < nx; ++i) {
            double *ex_ptr   = ex[i].data();
            const double *hz_ptr   = hz[i].data();
            const double *hz_prev_ptr = hz[i].data(); /* j-1 use same row */
            for (int j = 1; j < ny; ++j)
                ex_ptr[j] -= c1 * (hz_ptr[j] - hz_prev_ptr[j-1]);
        }

        /* 4. Update hz for i = 0..nx-2, j = 0..ny-2 */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 0; i < nx-1; ++i) {
            double *hz_ptr   = hz[i].data();
            const double *ex_ptr   = ex[i].data();
            const double *ex_ptr_next = ex[i+1].data();
            const double *ey_ptr   = ey[i].data();
            const double *ey_ptr_prev = ey[i].data(); /* same row for i */
            for (int j = 0; j < ny-1; ++j) {
                double ex_diff = ex_ptr[j+1] - ex_ptr[j];
                double ey_diff = ey_ptr_prev[j] - ey_ptr[j]; /* ey[i+1] vs ey[i] */
                hz_ptr[j] -= c2 * (ex_diff + ey_diff);
