#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_3mm(int ni, int nj, int nk, int nl, int nm,
		std::vector<std::vector<double>>& E,
		std::vector<std::vector<double>>& A,
		std::vector<std::vector<double>>& B,
		std::vector<std::vector<double>>& F,
		std::vector<std::vector<double>>& C,
		std::vector<std::vector<double>>& D,
		std::vector<std::vector<double>>& G) {

    /* ----------------------------------------------------------------
       1. Compute E = A * B   (ni x nk) * (nk x nj) -> (ni x nj)
       ---------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* Ei = E[i].data();          // pointer to E[i][0]
        const double* Ai = A[i].data();    // pointer to A[i][0]
        // Outer j loop inside for better cache locality
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            const double* Bj = &B[0][j];   // pointer to B[0][j]
            for (int k = 0; k < nk; ++k) {
                sum += Ai[k] * Bj[k];     // A[i][k] * B[k][j]
            }
            Ei[j] = sum;
        }
    }

    /* ----------------------------------------------------------------
       2. Compute F = C * D   (nj x nm) * (nm x nl) -> (nj x nl)
       ---------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < nj; ++i) {
        double* Fi = F[i].data();          // pointer to F[i][0]
        const double* Ci = C[i].data();    // pointer to C[i][0]
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            const double* Dj = &D[0][j];   // pointer to D[0][j]
            for (int k = 0; k < nm; ++k) {
                sum += Ci[k] * Dj[k];     // C[i][k] * D[k][j]
            }
            Fi[j] = sum;
        }
    }

    /* ----------------------------------------------------------------
       3. Compute G = E * F   (ni x nj) * (nj x nl) -> (ni x nl)
       ---------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* Gi = G[i].data();          // pointer to G[i][0]
        const double* Ei = E[i].data();    // pointer to E[i][0]
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            const double* Fj = &F[0][j];   // pointer to F[0][j]
            for (int k = 0; k < nj; ++k) {
                sum += Ei[k] * Fj[k];     // E[i][k] * F[k][j]
            }
            Gi[j] = sum;
        }
    }
}
