constexpr std::size_t BLOCK = 64;          // cache‑friendly tile size
constexpr std::size_t AVX_WIDTH = 4;       // elements processed in one SSE register

/* Helper that returns a pointer to the i‑th row of a 2‑D std::vector */
inline double* row(std::vector<std::vector<double>>& A, std::size_t i, std::size_t n)
{
    return A[i].data();
}

/* Main computational kernel */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    /* ---------- LU factorisation (lower & upper) ---------- */
    for (std::size_t bi = 0; bi < n; bi += BLOCK) {
        const std::size_t iMax = std::min(bi + BLOCK, (std::size_t)n);
#pragma omp parallel for schedule(static)
        for (std::size_t i = bi; i < iMax; ++i) {
            double* Ai = row(A, i, n);
            // lower part
            for (std::size_t j = 0; j < i; ++j) {
                double w = Ai[j];
                const double* Aij = row(A, i, n);
                const double* Akj = row(A, j, n);
                for (std::size_t k = 0; k < j; k += AVX_WIDTH) {
                    __m256d aik = _mm256_loadu_pd(&Aij[k]);   // A[i][k]
                    __m256d akj = _mm256_loadu_pd(&Akj[k]);   // A[j][k]
                    __m256d prod = _mm256_mul_pd(aik, akj);
                    __m256d wVec = _mm256_set1_pd(w);
                    wVec = _mm256_sub_pd(wVec, prod);
                    _mm256_storeu_pd(&Aij[k], wVec);
                }
                w = 0.0;
                for (std::size_t k = 0; k < j; ++k) w -= Aij[k] * Akj[k];
                Ai[j] = w / Akj[j];
            }
            // upper part
            for (std::size_t j = i; j < n; ++j) {
                double w = Ai[j];
                const double* Aij = row(A, i, n);
                const double* Aj = row(A, j, n);
                for (std::size_t k = 0; k < i; k += AVX_WIDTH) {
                    __m256d aik = _mm256_loadu_pd(&Aij[k]);   // A[i][k]
                    __m256d akj = _mm256_loadu_pd(&Aj[k]);    // A[k][j]
                    __m256d prod = _mm256_mul_pd(aik, akj);
                    __m256d wVec = _mm256_set1_pd(w);
                    wVec = _mm256_sub_pd(wVec, prod);
                    _mm256_storeu_pd(&Aij[k], wVec);
                }
                w = 0.0;
                for (std::size_t k = 0; k < i; ++k) w -= Aij[k] * Aj[k];
                Ai[j] = w;
            }
        }
    }

    /* ---------- Forward substitution: L * y = b ---------- */
    for (std::size_t i = 0; i < n; ++i) {
        double w = b[i];
        const double* Ai = row(A, i, n);
        for (std::size_t j = 0; j < i; ++j)
            w -= Ai[j] * y[j];
        y[i] = w;
    }

    /* ---------- Backward substitution: U * x = y ---------- */
    for (std::ptrdiff_t i = n - 1; i >= 0; --i) {
        double w = y[i];
        const double* Ai = row(A, i, n);
        for (std::size_t j = i + 1; j < n; ++j)
            w -= Ai[j] * x[j];
        x[i] = w / Ai[i];
    }
}
