/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_heat_3d(int tsteps,
		    int n,
		    std::vector<std::vector<std::vector<double>>>& A,
		    std::vector<std::vector<std::vector<double>>>& B)
{
    // Pre‑compute commonly used constants
    const double coeff = 0.125;   // 1/8
    const double two   = 2.0;

    // Derive layout information for flattening the 3‑D vectors.
    // We assume the innermost vector is contiguous (true for the
    // standard implementation of std::vector).  The outer vectors
    // provide the row-major ordering required for access patterns.
    const std::size_t nx = static_cast<std::size_t>(n);
    const std::size_t nxy = nx * nx;

    // Pointers to the underlying contiguous data.  We will access
    // them as flattened 1‑D arrays using the usual row‑major index:
    // idx(i,j,k) = i*nxy + j*nx + k
    double* Aflat = reinterpret_cast<double*>(A[0][0].data());
    double* Bflat = reinterpret_cast<double*>(B[0][0].data());

    const std::size_t stride_i = nxy;            // advance by a whole i‑plane
    const std::size_t stride_j = nx;             // advance by a whole j‑row
    const std::size_t stride_k = 1;              // advance by a scalar

    const std::size_t i_start = 1, i_end = n - 1;
    const std::size_t j_start = 1, j_end = n - 1;
    const std::size_t k_start = 1, k_end = n - 1;

    // Parallelise outermost loop over i to maximise spatial locality
    // and minimise false sharing (each thread operates on a distinct
    // slab of the 3‑D array).
#pragma omp parallel for schedule(static)
    for (int t = 1; t <= tsteps; ++t)
    {
        // --- update B from A ----------------------------------------
#pragma omp parallel for collapse(2) schedule(static)
        for (std::size_t i = i_start; i < i_end; ++i)
        {
            std::size_t idx_base = i * stride_i;
            for (std::size_t j = j_start; j < j_end; ++j)
            {
                std::size_t idx_ij = idx_base + j * stride_j;
                for (std::size_t k = k_start; k < k_end; ++k)
                {
                    std::size_t idx = idx_ij + k * stride_k;

                    // Laplacian in 3‑D with central differences
                    double center = Aflat[idx];
                    double val =
                          coeff * (Aflat[idx + stride_i] - two * center + Aflat[idx - stride_i])
                        + coeff * (Aflat[idx + stride_j] - two * center + Aflat[idx - stride_j])
                        + coeff * (Aflat[idx + stride_k] - two * center + Aflat[idx - stride_k])
                        + center;
                    Bflat[idx] = val;
                }
            }
        }

        // --- swap A and B (through copying) -----------------------
#pragma omp parallel for collapse(2) schedule(static)
        for (std::size_t i = i_start; i < i_end; ++i)
        {
            std::size_t idx_base = i * stride_i;
            for (std::size_t j = j_start; j < j_end; ++j)
            {
                std::size_t idx_ij = idx_base + j * stride_j;
                for (std::size_t k = k_start; k < k_end; ++k)
                {
                    std::size_t idx = idx_ij + k * stride_k;

                    double center = Bflat[idx];
                    double val =
                          coeff * (Bflat[idx + stride_i] - two * center + Bflat[idx - stride_i])
                        + coeff * (Bflat[idx + stride_j] - two * center + Bflat[idx - stride_j])
                        + coeff * (Bflat[idx + stride_k] - two * center + Bflat[idx - stride_k])
                        + center;
                    Aflat[idx] = val;
                }
            }
        }
    }
}
