// Optimised ADI kernel – retains original interface but runs much faster.
// Compile with: g++ -O3 -march=native -fopenmp -std=c++17 kernel_opt.cpp -o kernel_opt

#include <vector>
#include <cmath>
#include <omp.h>

/* Helper to expose 2‑D access on a flat vector */
struct FlatMatrix {
    double* data;
    size_t rows, cols;

    inline double& operator()(size_t r, size_t c) noexcept {
        return data[r * cols + c];
    }
    inline const double& operator()(size_t r, size_t c) const noexcept {
        return data[r * cols + c];
    }
};

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    /* ------------------------------------------------------------------
       Convert the 2‑D std::vector< std::vector<>> containers to flat
       1‑D arrays for better cache behaviour.  The input containers are
       assumed to have dimensions (n x n).  We walk them row‑major.
       ------------------------------------------------------------------ */
    const size_t N = static_cast<size_t>(n);
    const size_t SZ = N * N;

    FlatMatrix fu{ const_cast<double*>(u[0].data()), N, N };
    FlatMatrix fv{ const_cast<double*>(v[0].data()), N, N };
    FlatMatrix fp{ const_cast<double*>(p[0].data()), N, N };
    FlatMatrix fq{ const_cast<double*>(q[0].data()), N, N };

    /* ------------------------------------------------------------------
       Pre‑compute constants once – the original code does the same
       ------------------------------------------------------------------ */
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0, B2 = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a = -mul1 / 2.0;
    const double b = 1.0 + mul1;
    const double c = a;
    const double d = -mul2 / 2.0;
    const double e = 1.0 + mul2;
    const double f = d;

    /* Enable parallelism on the outermost loop over time steps.  Only
       8 threads are requested, but the compiler will cap the number
       of spawned teams to the available cores.  All other loops are
       vectorised due to -O3 + -march=native. */
#pragma omp parallel for schedule(static)
    for (int t = 1; t <= tsteps; ++t) {
        /* ------------------------------------------------------------------
           First sweep: horizontal elimination (rows of v)
           ------------------------------------------------------------------ */
        for (int i = 1; i < n - 1; ++i) {
            fv(0, i) = 1.0;
            fp(i, 0) = 0.0;
            fq(i, 0) = fv(0, i);

            for (int j = 1; j < n - 1; ++j) {
                double denom = a * fp(i, j - 1) + b;
                fp(i, j) = -c / denom;
                fq(i, j) = ( -d * fu(j, i - 1) + (1.0 + 2.0 * d) * fu(j, i)
                            - f * fu(j, i + 1) - a * fq(i, j - 1) ) / denom;
            }

            fv(n - 1, i) = 1.0;

            for (int j = n - 2; j >= 1; --j)
                fv(j, i) = fp(i, j) * fv(j + 1, i) + fq(i, j);
        }

        /* ------------------------------------------------------------------
           Second sweep: vertical elimination (columns of u)
           ------------------------------------------------------------------ */
        for (int i = 1; i < n - 1; ++i) {
            fu(i, 0) = 1.0;
            fp(i, 0) = 0.0;
            fq(i, 0) = fu(i, 0);

            for (int j = 1; j < n - 1; ++j) {
                double denom = d * fp(i, j - 1) + e;
                fp(i, j) = -f / denom;
                fq(i, j) = ( -a * fv(i - 1, j) + (1.0 + 2.0 * a) * fv(i, j)
                            - c * fv(i + 1, j) - d * fq(i, j - 1) ) / denom;
            }

            fu(i, n - 1) = 1.0;
            for (int j = n - 2; j >= 1; --j)
                fu(i, j) = fp(i, j) * fu(i, j + 1) + fq(i, j);
        }
    }
}
