#include <cmath>
#include <vector>
#include <omp.h>

/* Optimised kernel_deriche – preserves exact behaviour */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* Pre‑compute constants only once */
    const float expA  = std::exp(-alpha);
    const float exp2A = expA * expA;
    const float k = 1.0f - expA * (1.0f - expA) /
                    (1.0f + 2.0f * static_cast<float>(alpha) * expA - exp2A);

    const float a1 = k,           a5 = k;
    const float a2 = a6 = k * expA * (static_cast<float>(alpha) - 1.0f);
    const float a3 = a7 = k * expA * (static_cast<float>(alpha) + 1.0f);
    const float a4 = a8 = -k * exp2A;
    const float b1 = std::pow(2.0f, -static_cast<float>(alpha));
    const float b2 = -exp2A;
    const float c1 = 1.0f, c2 = 1.0f;

    /* Forward horizontal pass */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        std::vector<float> &yin  = imgIn[i];
        std::vector<float> &y1in = y1[i];

        for (int j = 0; j < h; ++j) {
            const float x = yin[j];
            const float y = a1 * x + a2 * xm1 + b1 * ym1 + b2 * ym2;
            y1in[j] = y;
            xm1 = x;  ym2 = ym1;  ym1 = y;
        }
    }

    /* Backward horizontal pass */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        const std::vector<float> &yin  = imgIn[i];
        std::vector<float> &y2in = y2[i];

        for (int j = h - 1; j >= 0; --j) {
            const float y = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            y2in[j] = y;
            xp2 = xp1;  xp1 = yin[j];
            yp2 = yp1;  yp1 = y;
        }
    }

    /* Combine columns */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        std::vector<float> &yin  = imgIn[i];
        std::vector<float> &y1in = y1[i];
        std::vector<float> &y2in = y2[i];
        std::vector<float> &out  = imgOut[i];

        for (int j = 0; j < h; ++j)
            out[j] = c1 * (y1in[j] + y2in[j]);
    }

    /* Forward vertical pass */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const float x = imgOut[i][j];
            const float y = a5 * x + a6 * tm1 + b1 * ym1 + b2 * ym2;
            y1[i][j] = y;
            tm1 = x;  ym2 = ym1;  ym1 = y;
        }
    }

    /* Backward vertical pass */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w - 1; i >= 0; --i) {
            const float y = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            y2[i][j] = y;
            tp2 = tp1;  tp1 = imgOut[i][j];
            yp2 = yp1;  yp1 = y;
        }
    }

    /* Final combination */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        const std::vector<float> &y1in = y1[i];
        const std::vector<float> &y2in = y2[i];
        std::vector<float> &out = imgOut[i];

        for (int j = 0; j < h; ++j)
            out[j] = c2 * (y1in[j] + y2in[j]);
    }
}
